import { DsButtonComponent } from './ng-bank-button.component';
const meta = {
    title: 'NG Bank/Button (Override)',
    component: DsButtonComponent,
    tags: ['autodocs'],
    argTypes: {
        variant: {
            control: 'select',
            options: ['primary', 'secondary', 'warn'],
        },
        disabled: { control: 'boolean' },
        icon: { control: 'text' },
        type: {
            control: 'select',
            options: ['button', 'submit', 'reset'],
        },
    },
};
export default meta;
export const Primary = {
    render: (args) => ({
        props: args,
        template: `<ds-button [variant]="variant" [disabled]="disabled" [icon]="icon">Primary</ds-button>`,
    }),
    args: {
        variant: 'primary',
        disabled: false,
    },
};
export const Secondary = {
    render: (args) => ({
        props: args,
        template: `<ds-button [variant]="variant" [disabled]="disabled">Secondary</ds-button>`,
    }),
    args: {
        variant: 'secondary',
        disabled: false,
    },
};
export const WithIcon = {
    render: (args) => ({
        props: args,
        template: `<ds-button [variant]="variant" [icon]="icon">With Icon</ds-button>`,
    }),
    args: {
        variant: 'primary',
        icon: 'arrow_forward',
    },
};
export const Disabled = {
    render: (args) => ({
        props: args,
        template: `<ds-button [variant]="variant" [disabled]="true">Disabled</ds-button>`,
    }),
    args: {
        variant: 'primary',
    },
};
export const AllVariants = {
    render: () => ({
        template: `
      <div style="display:flex; gap:1rem; flex-wrap:wrap; align-items:center;">
        <ds-button variant="primary">Primary</ds-button>
        <ds-button variant="secondary">Secondary</ds-button>
        <ds-button variant="warn">Warn</ds-button>
        <ds-button variant="primary" icon="arrow_forward">With Icon</ds-button>
        <ds-button variant="primary" [disabled]="true">Disabled</ds-button>
      </div>
    `,
    }),
};
